import type * as DMMF from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 */
export function scalarTypeToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      // Enums and relation types are referenced by name.
      return prismaType
  }
}

/**
 * Returns the TypeScript type annotation for a DMMF field, accounting for
 * list and optionality modifiers.
 */
export function fieldToTsType(field: DMMF.Field): string {
  const base = field.kind === 'object' ? field.type : scalarTypeToTs(field.type)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/**
 * Returns the name of the ID (or first unique scalar) field for a model, used
 * to type the `where` clause in single-record operations.  Falls back to the
 * first field when no explicit ID is found.
 */
export function idFieldOf(model: DMMF.Model): DMMF.Field {
  return (
    model.fields.find((f) => f.isId) ??
    model.fields.find((f) => f.isUnique && f.kind === 'scalar') ??
    model.fields[0]
  )
}

/**
 * Renders the TypeScript `interface` block for a single Prisma model,
 * including only scalar and enum fields (relation fields are omitted because
 * they depend on other generated types).
 */
export function renderModelInterface(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind !== 'object')
  const fieldLines = scalarFields.map((f) => `  ${f.name}: ${fieldToTsType(f)}`)
  return [`export interface ${model.name} {`, ...fieldLines, '}'].join('\n')
}

/**
 * Renders a `*RestClient` interface with typed CRUD methods for a model.
 */
export function renderRestClientInterface(model: DMMF.Model): string {
  const id = idFieldOf(model)
  const idType = scalarTypeToTs(id.type)
  const name = model.name

  const lines = [
    `export interface ${name}RestClient {`,
    `  findMany(params?: { skip?: number; take?: number; where?: Partial<${name}> }): Promise<${name}[]>`,
    `  findUnique(params: { where: { ${id.name}: ${idType} } }): Promise<${name} | null>`,
    `  create(params: { data: Omit<${name}, '${id.name}'> }): Promise<${name}>`,
    `  update(params: { where: { ${id.name}: ${idType} }; data: Partial<${name}> }): Promise<${name}>`,
    `  delete(params: { where: { ${id.name}: ${idType} } }): Promise<${name}>`,
    '}',
  ]
  return lines.join('\n')
}

/**
 * Renders the top-level `RestClient` interface that groups all per-model
 * clients under a property named after the camelCase model name.
 */
export function renderRootInterface(models: readonly DMMF.Model[]): string {
  const props = models.map((m) => {
    const prop = m.name.charAt(0).toLowerCase() + m.name.slice(1)
    return `  ${prop}: ${m.name}RestClient`
  })
  return ['export interface RestClient {', ...props, '}'].join('\n')
}

/**
 * Assembles the full contents of the generated `rest-client.ts` file.
 */
export function renderFile(models: readonly DMMF.Model[]): string {
  const sections: string[] = ['// Auto-generated by @prisma/generator-rest-client. Do not edit manually.', '']

  for (const model of models) {
    sections.push(renderModelInterface(model))
    sections.push('')
    sections.push(renderRestClientInterface(model))
    sections.push('')
  }

  sections.push(renderRootInterface(models))
  sections.push('')

  return sections.join('\n')
}

