import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { renderFile } from './template'

/**
 * Resolves the absolute output directory from the generator config.
 * Falls back to a `generated/rest-client` sibling of the schema file when no
 * explicit output is configured.
 */
function resolveOutputDir(options: GeneratorOptions): string {
  const outputValue = options.generator.output?.value
  if (outputValue) {
    return path.isAbsolute(outputValue) ? outputValue : path.resolve(outputValue)
  }
  return path.join(path.dirname(options.schemaPath), 'generated', 'rest-client')
}

/**
 * Reads the DMMF from `options`, generates the REST client TypeScript source,
 * and writes it to `<outputDir>/rest-client.ts`.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)
  await fs.mkdir(outputDir, { recursive: true })

  const models = options.dmmf.datamodel.models
  const content = renderFile(models)

  const outputFile = path.join(outputDir, 'rest-client.ts')
  await fs.writeFile(outputFile, content, 'utf-8')
}

